import Security.MonoalphabeticCipher;
import org.junit.jupiter.api.Test;
import java.util.*;
import java.util.stream.IntStream;
import java.util.regex.Pattern;

import static org.junit.jupiter.api.Assertions.*;

public class MonoalphabeticCipherTest {

    private final MonoalphabeticCipher algorithm = new MonoalphabeticCipher();

    // Test Data
    String mainPlain = "meetmeafterthetogaparty";
    String mainCipher = "phhwphdiwhuwkhwrjdsduwb".toUpperCase();
    String mainKey = "defghijklmnopqrstuvwxyzabc";

    String mainPlain1 = "abcdefghijklmnopqrstuvwxyz";
    String mainCipher1 = "isyvkjruxedzqmctplofnbwgah".toUpperCase();
    String mainKey1 = "isyvkjruxedzqmctplofnbwgah";

    String mainPlain2 = "hellosecuritymonoalphabetic";
    String mainCipher2 = "ukzzcokynlxfaqcmciztuiskfxy".toUpperCase();

    String newPlain = "ENGLISHASTRONOMERWILLIAMLASSELLDISCOVEREDTRITON".toLowerCase();
    String newCipher = "EGSDAMTUMOLHGHFELWADDAUFDUMMEDDVAMIHQELEVOLAOHG".toUpperCase();
    String newKey = "UNIVERSTABCDFGHJKLMOPQWXYZ".toLowerCase();

    // Large test data for Frequency Analysis
    String largePlain = "".toLowerCase();
    String largeCipher = "".toUpperCase();
    String largeKey = "defghijklmnopqrstuvwxyzabc";

    @Test
    public void monoTestAnalysisFrequency() {
        String plain = algorithm.analyseUsingCharFrequency(largeCipher);

        // Count matching characters between expected and actual
        long count = IntStream.range(0, largePlain.length())
                .filter(i -> largePlain.charAt(i) == plain.charAt(i))
                .count();

        assertTrue((count * 100.0 / largePlain.length()) > 70);
    }

}
